# Wrong: no detach on model-output token used as next input
def bad_ss_step(logits, gt_token, eps):
    import random
    if random.random() < eps:
        return gt_token
    return logits.argmax(dim=-1, keepdim=True)  # missing .detach()

# Correct: detach model output before feeding as next input
def good_ss_step(logits, gt_token, eps):
    import random
    if random.random() < eps:
        return gt_token
    return logits.argmax(dim=-1, keepdim=True).detach()  # detached

import math

def get_tf_prob(global_step: int, warmup_steps: int = 30000, k: float = 5000.0) -> float:
    """Inverse sigmoid scheduled sampling probability (teacher forcing rate)."""
    if global_step < warmup_steps:
        return 1.0  # pure teacher forcing warm-up
    ss_step = global_step - warmup_steps
    return k / (k + math.exp(ss_step / k))

# Example: at step 40k (10k into ss phase): ~0.87 TF, 0.13 model
# At step 80k (50k into ss phase): ~0.14 TF, 0.86 model
for step in [0, 30000, 40000, 60000, 80000]:
    print(f"Step {step:6d}: TF prob = {get_tf_prob(step):.3f}")
